/// <summary>
/// Pure C# tree-ensemble inference, generated from the ONNX model files.
/// Eliminates the Microsoft.ML.OnnxRuntime dependency.
/// </summary>
public static class NativeTreeModels
{
    private static double Sigmoid(double x) => 1.0 / (1.0 + Math.Exp(-x));

    private static double RunTrees(
        float[] features,
        float[] scalerOffset, float[] scalerScale,
        double baseValue,
        int[] treeStarts, bool[] isLeaf, int[] featIds,
        float[] thresholds, int[] trueChild, int[] falseChild,
        float[] leafWeights)
    {
        var scaled = new double[features.Length];
        for (int i = 0; i < scalerOffset.Length; i++)
            scaled[i] = (features[i] - scalerOffset[i]) * scalerScale[i];
        for (int i = scalerOffset.Length; i < features.Length; i++)
            scaled[i] = features[i];
        double score = baseValue;
        for (int t = 0; t < treeStarts.Length; t++)
        {
            int root = treeStarts[t];
            int idx = root;
            while (!isLeaf[idx])
            {
                idx = scaled[featIds[idx]] <= thresholds[idx]
                    ? root + trueChild[idx]
                    : root + falseChild[idx];
            }
            score += leafWeights[idx];
        }
        return Sigmoid(score);
    }

