    //  Donor Churn -- One-Hot Encoding Helper
    // =================================================================
    private static readonly string[][] DonorChurnCategories = {
        new[] { "MonetaryDonor", "PartnerOrganization", "SkillsContributor", "SocialMediaAdvocate", "Volunteer" },
        new[] { "Event", "PartnerReferral", "SocialMedia", "Website", "WordOfMouth" },
        new[] { "Mindanao", "Visayas" },
        new[] { "Local", "PartnerOrganization" },
        new[] { "Direct", "Event", "Other", "SocialMedia" },
        new[] { "Maintenance", "Operations", "Other", "Transport", "Wellbeing" },
    };

    public static float[] BuildDonorChurnFeatures(float[] numericFeatures, string[] categoricalValues)
    {
        var ohe = new List<float>();
        for (int c = 0; c < DonorChurnCategories.Length; c++)
        {
            var cats = DonorChurnCategories[c];
            for (int i = 0; i < cats.Length; i++)
                ohe.Add(cats[i] == categoricalValues[c] ? 1f : 0f);
        }
        var features = new float[numericFeatures.Length + ohe.Count];
        numericFeatures.CopyTo(features, 0);
        for (int i = 0; i < ohe.Count; i++)
            features[numericFeatures.Length + i] = ohe[i];
        return features;
    }
